98,128,.2);font-weight:600;transition:transform .2s ease,background .2s ease,color .2s ease}nav a:hover{background:rgba(40,144,198,.18);color:var(--ink);transform:translateY(-1px)}main{padding:48px 0 60px}footer{background-color:var(--ink);color:#fdf3ee;text-align:center;padding:22px 0;margin-top:30px}.btn{display:inline-flex;align-items:center;gap:8px;padding:10px 18px;border-radius:999px;text-decoration:none;font-weight:600;border:1px solid transparent;transition:transform .2s ease,box-shadow .2s ease}.btn-primary{background:linear-gradient(120deg,var(--accent),var(--navy));color:#fff;box-shadow:0 8px 18px rgba(40,144,198,.25)}.btn-outline{color:var(--navy);background:rgba(255,255,255,.7);border-color:rgba(64,98,128,.35)}.btn-muted{background:rgba(95,102,147,.12);color:var(--ink);border-color:rgba(95,102,147,.35)}.btn:hover{transform:translateY(-1px)}.panel{background:var(--panel);border-radius:18px;box-shadow:var(--shadow);border:1px solid rgba(56,40,51,.08)}@media (max-width:700px){header{padding:30px 0 34px}nav a{width:100%;justify-content:center}.nav-links{width:100%}}</style></head><body><?php View::partial('frontend/header.php',['title'=>$title ?? null]); ?><?php View::partial('frontend/nav.php'); ?><main><div class="container"><?=$content?></div></main><?php View::partial('frontend/footer.php'); ?></body></html>